// core/pdf-engine.js — PDF generation engine using jsPDF
// Embedded logos (base64 PNG, processed from official files)
window.LOGO_WCG = '';
window.LOGO_NHLS = '';
window.LOGO_EMS = '';


// All modules use this to generate their replicated form PDFs

window.PDFEngine = {

  // Shared style constants
  styles: {
    pageMargin: 20,
    lineHeight: 7,
    fieldHeight: 8,
    sectionGap: 6,
    colors: {
      headerBg: [0, 83, 141],      // WCG DoH dark blue
      headerText: [255, 255, 255],
      sectionBg: [220, 234, 245],
      sectionText: [0, 55, 100],
      labelText: [60, 60, 60],
      valueText: [10, 10, 10],
      border: [180, 180, 180],
      fieldBg: [248, 250, 252],
      accentLine: [0, 150, 214],   // WCG light blue accent
    }
  },

  // Create a new jsPDF document with standard setup
  newDoc() {
    const doc = new jspdf.jsPDF({ unit: 'mm', format: 'a4' });
    doc.setFont('helvetica');
    return doc;
  },

  // Draw the standard Victoria Hospital EC header
  drawHeader(doc, formTitle, refNumber) {
    const { colors } = this.styles;
    const W = 210, M = this.styles.pageMargin;

    // Header background
    doc.setFillColor(...colors.headerBg);
    doc.rect(0, 0, W, 28, 'F');

    // Accent stripe
    doc.setFillColor(...colors.accentLine);
    doc.rect(0, 28, W, 2, 'F');

    // Institution name
    doc.setTextColor(...colors.headerText);
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    doc.text('VICTORIA HOSPITAL — EMERGENCY CENTRE', M, 11);

    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    doc.text('Western Cape Department of Health', M, 17);
    doc.text('Accounts & Access Request System', M, 22);

    // Form title block (right-aligned)
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text(formTitle, W - M, 13, { align: 'right' });

    if (refNumber) {
      doc.setFontSize(8);
      doc.setFont('helvetica', 'normal');
      doc.text(`Ref: ${refNumber}`, W - M, 19, { align: 'right' });
    }

    // Date generated
    const today = new Date().toLocaleDateString('en-ZA', {
      day: '2-digit', month: 'long', year: 'numeric'
    });
    doc.setFontSize(7.5);
    doc.text(`Generated: ${today}`, W - M, 25, { align: 'right' });

    doc.setTextColor(0, 0, 0);
    return 35; // return Y position after header
  },

  // Draw a section heading bar
  drawSection(doc, title, y) {
    const { colors, styles } = this;
    const W = 210, M = styles.pageMargin;
    const usableW = W - M * 2;

    doc.setFillColor(...colors.sectionBg);
    doc.rect(M, y, usableW, 7, 'F');
    doc.setDrawColor(...colors.accentLine);
    doc.setLineWidth(0.5);
    doc.line(M, y, M, y + 7);

    doc.setFontSize(8.5);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...colors.sectionText);
    doc.text(title.toUpperCase(), M + 3, y + 5);
    doc.setTextColor(0, 0, 0);

    return y + 10;
  },

  // Draw a labeled field with value
  drawField(doc, label, value, x, y, width) {
    const { colors } = this.styles;
    const fieldH = 9;

    // Field background
    doc.setFillColor(...colors.fieldBg);
    doc.setDrawColor(...colors.border);
    doc.setLineWidth(0.3);
    doc.rect(x, y, width, fieldH, 'FD');

    // Label
    doc.setFontSize(6.5);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(...colors.labelText);
    doc.text(label, x + 2, y + 3.5);

    // Value
    doc.setFontSize(8.5);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...colors.valueText);
    const displayVal = value && value.trim() !== '' ? value : '___________________________';
    doc.text(displayVal, x + 2, y + 7.5);

    doc.setTextColor(0, 0, 0);
    doc.setFont('helvetica', 'normal');
  },

  // Draw two fields side by side
  drawFieldRow(doc, fields, y) {
    const M = this.styles.pageMargin;
    const usableW = 210 - M * 2;
    const gap = 3;
    const colW = (usableW - gap * (fields.length - 1)) / fields.length;

    fields.forEach((field, i) => {
      const x = M + i * (colW + gap);
      this.drawField(doc, field.label, field.value || '', x, y, colW);
    });

    return y + 12;
  },

  // Draw a checkbox item
  drawCheckbox(doc, label, checked, x, y) {
    doc.setDrawColor(...this.styles.colors.border);
    doc.setLineWidth(0.4);
    doc.rect(x, y, 4, 4, 'D');
    if (checked) {
      doc.setDrawColor(0, 120, 60);
      doc.setLineWidth(0.8);
      doc.line(x + 0.8, y + 2, x + 1.8, y + 3.2);
      doc.line(x + 1.8, y + 3.2, x + 3.4, y + 0.8);
    }
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(30, 30, 30);
    doc.text(label, x + 6, y + 3.2);
    doc.setTextColor(0, 0, 0);
    return y + 7;
  },

  // Draw signature block
  drawSignatureBlock(doc, y, roles) {
    const M = this.styles.pageMargin;
    const usableW = 210 - M * 2;
    const colW = (usableW - 6 * (roles.length - 1)) / roles.length;

    y = this.drawSection(doc, 'Authorisation & Signatures', y);

    roles.forEach((role, i) => {
      const x = M + i * (colW + 6);
      doc.setDrawColor(...this.styles.colors.border);
      doc.setLineWidth(0.3);

      // Signature line
      doc.line(x, y + 14, x + colW, y + 14);
      doc.setFontSize(7);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(60, 60, 60);
      doc.text(role.toUpperCase(), x, y + 18);
      doc.setFont('helvetica', 'normal');
      doc.text('Signature & Date', x, y + 22);
      doc.setTextColor(0, 0, 0);
    });

    return y + 28;
  },

  // Draw footer
  drawFooter(doc, pageNum) {
    const y = 287;
    doc.setFillColor(...this.styles.colors.headerBg);
    doc.rect(0, y, 210, 10, 'F');
    doc.setFontSize(7);
    doc.setTextColor(200, 220, 240);
    doc.setFont('helvetica', 'normal');
    doc.text('Victoria Hospital EC — Accounts & Access Request', 20, y + 6);
    doc.text(`Page ${pageNum}  |  CONFIDENTIAL — Do not circulate`, 190, y + 6, { align: 'right' });
    doc.setTextColor(0, 0, 0);
  },

  // Save and trigger download
  save(doc, filename) {
    doc.save(filename);
  }
};
